import { useEffect, useState } from "react";
import {
  createUserWithEmailAndPassword,
  onAuthStateChanged,
  signInWithEmailAndPassword,
  signOut,
} from "firebase/auth";
import {
  onValue,
  push,
  ref,
  runTransaction,
  serverTimestamp,
} from "firebase/database";
import "./App.css";
import { APP_VERSION, DOWNLOAD_URL, REMOTE_VERSION_URL } from "./config";
import { auth, database, isFirebaseConfigured } from "./firebase";

const emptyBoard = Array(9).fill(null);
const allowedEmails = [
  "dhomeasmari@gmail.com",
  "lojainyousf5@gmail.com",
];
const securityQuestion = "وش شخصية دحوم في أوفرواتش يا أجمل لجين؟";
const securityAnswer = "widowmaker";

function formatStamp(value) {
  if (!value) return "الآن";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "الآن";
  return new Intl.DateTimeFormat("ar", {
    dateStyle: "medium",
    timeStyle: "short",
  }).format(date);
}

function checkWinner(board) {
  const lines = [
    [0, 1, 2],
    [3, 4, 5],
    [6, 7, 8],
    [0, 3, 6],
    [1, 4, 7],
    [2, 5, 8],
    [0, 4, 8],
    [2, 4, 6],
  ];

  for (const [a, b, c] of lines) {
    if (board[a] && board[a] === board[b] && board[a] === board[c]) {
      return board[a];
    }
  }

  return board.every(Boolean) ? "draw" : null;
}

function compareVersions(currentVersion, nextVersion) {
  const current = currentVersion.split(".").map(Number);
  const next = nextVersion.split(".").map(Number);
  const length = Math.max(current.length, next.length);

  for (let index = 0; index < length; index += 1) {
    const currentPart = current[index] || 0;
    const nextPart = next[index] || 0;

    if (nextPart > currentPart) return 1;
    if (nextPart < currentPart) return -1;
  }

  return 0;
}

function App() {
  const logoSrc = `${process.env.PUBLIC_URL || ""}/app-logo.jpg`;
  const [installPrompt, setInstallPrompt] = useState(null);
  const [isInstalled, setIsInstalled] = useState(false);
  const [activeSection, setActiveSection] = useState("chat");
  const [authMode, setAuthMode] = useState("login");
  const [securityInput, setSecurityInput] = useState("");
  const [securityPassed, setSecurityPassed] = useState(false);
  const [securityError, setSecurityError] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [authError, setAuthError] = useState("");
  const [authLoading, setAuthLoading] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);
  const [accessError, setAccessError] = useState("");
  const [updateInfo, setUpdateInfo] = useState({
    loading: false,
    available: false,
    latestVersion: APP_VERSION,
    downloadUrl: DOWNLOAD_URL,
    message: "",
  });

  const [chatMessage, setChatMessage] = useState("");
  const [messages, setMessages] = useState([]);

  const [memoryTitle, setMemoryTitle] = useState("");
  const [memoryText, setMemoryText] = useState("");
  const [memoryImageUrl, setMemoryImageUrl] = useState("");
  const [memories, setMemories] = useState([]);

  const [game, setGame] = useState({
    board: emptyBoard,
    nextTurn: "X",
    winner: null,
    players: { X: null, O: null },
  });

  useEffect(() => {
    const handleBeforeInstallPrompt = (event) => {
      event.preventDefault();
      setInstallPrompt(event);
    };

    const checkStandalone = () => {
      const standalone =
        window.matchMedia("(display-mode: standalone)").matches ||
        window.navigator.standalone === true;
      setIsInstalled(standalone);
    };

    window.addEventListener("beforeinstallprompt", handleBeforeInstallPrompt);
    window.addEventListener("appinstalled", checkStandalone);
    checkStandalone();

    return () => {
      window.removeEventListener(
        "beforeinstallprompt",
        handleBeforeInstallPrompt
      );
      window.removeEventListener("appinstalled", checkStandalone);
    };
  }, []);

  useEffect(() => {
    checkForUpdates();
  }, []);

  useEffect(() => {
    if (!isFirebaseConfigured || !auth) return undefined;

    const unsubscribe = onAuthStateChanged(auth, (user) => {
      if (!user?.email) {
        setCurrentUser(user);
        setAccessError("");
        return;
      }

      const normalizedEmail = user.email.toLowerCase();
      if (!allowedEmails.includes(normalizedEmail)) {
        setAccessError("هذا المكان سويته للين فقط، وهذا الإيميل مو مخصص له.");
        setCurrentUser(null);
        signOut(auth);
        return;
      }

      setAccessError("");
      setCurrentUser(user);
    });

    return unsubscribe;
  }, []);

  useEffect(() => {
    if (!currentUser || !database) {
      setMessages([]);
      setMemories([]);
      return undefined;
    }

    const messagesRef = ref(database, "chat/messages");
    const memoriesRef = ref(database, "memories/items");
    const gameRef = ref(database, "games/ticTacToe");

    const stopMessages = onValue(messagesRef, (snapshot) => {
      const value = snapshot.val() || {};
      const nextMessages = Object.entries(value)
        .map(([id, item]) => ({ id, ...item }))
        .sort((a, b) => (a.createdAt || 0) - (b.createdAt || 0));
      setMessages(nextMessages);
    });

    const stopMemories = onValue(memoriesRef, (snapshot) => {
      const value = snapshot.val() || {};
      const nextMemories = Object.entries(value)
        .map(([id, item]) => ({ id, ...item }))
        .sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
      setMemories(nextMemories);
    });

    const stopGame = onValue(gameRef, (snapshot) => {
      const value = snapshot.val();
      if (!value) {
        setGame({
          board: emptyBoard,
          nextTurn: "X",
          winner: null,
          players: { X: null, O: null },
        });
        return;
      }
      setGame({
        board: value.board || emptyBoard,
        nextTurn: value.nextTurn || "X",
        winner: value.winner || null,
        players: value.players || { X: null, O: null },
      });
    });

    return () => {
      stopMessages();
      stopMemories();
      stopGame();
    };
  }, [currentUser]);

  const handleAuth = async (event) => {
    event.preventDefault();
    setAuthError("");
    setAuthLoading(true);

    try {
      if (authMode === "login") {
        await signInWithEmailAndPassword(auth, email, password);
      } else {
        await createUserWithEmailAndPassword(auth, email, password);
      }
      setPassword("");
    } catch (error) {
      setAuthError("ما ضبط الدخول الآن، جرّبي مرة ثانية يا أجمل شخص عندي.");
    } finally {
      setAuthLoading(false);
    }
  };

  const handleSecurityCheck = (event) => {
    event.preventDefault();
    const normalizedAnswer = securityInput.trim().toLowerCase();

    if (normalizedAnswer === securityAnswer) {
      setSecurityPassed(true);
      setSecurityError("");
      return;
    }

    setSecurityError("الإجابة مو هي، لكني متأكد إنك تعرفينها.");
  };

  const handleInstallApp = async () => {
    if (!installPrompt) return;

    await installPrompt.prompt();
    await installPrompt.userChoice;
    setInstallPrompt(null);
  };

  const checkForUpdates = async () => {
    setUpdateInfo((current) => ({
      ...current,
      loading: true,
      message: "",
    }));

    try {
      const response = await fetch(
        `${REMOTE_VERSION_URL}?t=${Date.now()}`,
        { cache: "no-store" }
      );

      if (!response.ok) {
        throw new Error("version-check-failed");
      }

      const payload = await response.json();
      const latestVersion = payload.version || APP_VERSION;
      const hasUpdate = compareVersions(APP_VERSION, latestVersion) === 1;

      setUpdateInfo({
        loading: false,
        available: hasUpdate,
        latestVersion,
        downloadUrl: payload.downloadUrl || DOWNLOAD_URL,
        message: hasUpdate ? "نزلت لك نسخة أجمل يا لجين." : "هذا آخر إصدار سويته لك.",
      });
    } catch (error) {
      setUpdateInfo({
        loading: false,
        available: false,
        latestVersion: APP_VERSION,
        downloadUrl: DOWNLOAD_URL,
        message: "ما قدرت أتأكد من التحديث الآن، جرّبي بعد شوي.",
      });
    }
  };

  const openDownloadLink = () => {
    window.open(updateInfo.downloadUrl || DOWNLOAD_URL, "_blank", "noopener,noreferrer");
  };

  const handleSendMessage = async (event) => {
    event.preventDefault();
    const trimmedMessage = chatMessage.trim();
    if (!trimmedMessage || !currentUser || !database) return;

    await push(ref(database, "chat/messages"), {
      text: trimmedMessage,
      userId: currentUser.uid,
      author: currentUser.email,
      createdAt: Date.now(),
      serverAt: serverTimestamp(),
    });

    setChatMessage("");
  };

  const handleAddMemory = async (event) => {
    event.preventDefault();
    if (!currentUser || !database) return;

    const title = memoryTitle.trim();
    const text = memoryText.trim();
    const imageUrl = memoryImageUrl.trim();

    if (!title && !text && !imageUrl) return;

    await push(ref(database, "memories/items"), {
      title: title || "ذكرى جديدة",
      text,
      imageUrl,
      author: currentUser.email,
      userId: currentUser.uid,
      createdAt: Date.now(),
      serverAt: serverTimestamp(),
    });

    setMemoryTitle("");
    setMemoryText("");
    setMemoryImageUrl("");
  };

  const joinAsPlayer = async (symbol) => {
    if (!currentUser || !database) return;

    await runTransaction(ref(database, "games/ticTacToe"), (current) => {
      const next = current || {
        board: emptyBoard,
        nextTurn: "X",
        winner: null,
        players: { X: null, O: null },
      };

      if (
        next.players?.[symbol] &&
        next.players[symbol].uid !== currentUser.uid
      ) {
        return next;
      }

      return {
        ...next,
        players: {
          X: next.players?.X || null,
          O: next.players?.O || null,
          [symbol]: {
            uid: currentUser.uid,
            email: currentUser.email,
          },
        },
      };
    });
  };

  const handleSquareClick = async (index) => {
    if (!currentUser || !database) return;

    await runTransaction(ref(database, "games/ticTacToe"), (current) => {
      const next = current || {
        board: emptyBoard,
        nextTurn: "X",
        winner: null,
        players: { X: null, O: null },
      };

      if (next.winner || next.board[index]) return next;

      const currentPlayer = next.players?.[next.nextTurn];
      if (!currentPlayer || currentPlayer.uid !== currentUser.uid) return next;

      const updatedBoard = [...next.board];
      updatedBoard[index] = next.nextTurn;
      const winner = checkWinner(updatedBoard);

      return {
        ...next,
        board: updatedBoard,
        winner,
        nextTurn: next.nextTurn === "X" ? "O" : "X",
        updatedAt: Date.now(),
      };
    });
  };

  const resetGame = async () => {
    if (!database) return;

    await runTransaction(ref(database, "games/ticTacToe"), (current) => ({
      board: emptyBoard,
      nextTurn: "X",
      winner: null,
      players: current?.players || { X: null, O: null },
      updatedAt: Date.now(),
    }));
  };

  const currentPlayerSymbol =
    game.players?.X?.uid === currentUser?.uid
      ? "X"
      : game.players?.O?.uid === currentUser?.uid
        ? "O"
        : null;

  if (!isFirebaseConfigured) {
    return (
      <div className="app-shell setup-shell">
        <div className="setup-card">
          <img className="app-logo setup-logo" src={logoSrc} alt="شعار التطبيق" />
          <p className="eyebrow">Just One Last Step</p>
          <h1>باقي لمسة صغيرة ويكتمل المكان</h1>
          <p>
            أنا جهزت هذا التطبيق كله عشانك، وباقي فقط إعداد Firebase حتى يشتغل كامل.
          </p>
          <div className="setup-steps">
            <p>1. افتح Firebase Console وأنشئ Web App.</p>
            <p>2. فعّل Email/Password من Authentication.</p>
            <p>3. أنشئ Realtime Database.</p>
            <p>4. أضف القيم داخل <code>src/firebase.js</code>.</p>
          </div>
          <pre className="code-block">
{`REACT_APP_FIREBASE_API_KEY=...
REACT_APP_FIREBASE_AUTH_DOMAIN=...
REACT_APP_FIREBASE_DATABASE_URL=...
REACT_APP_FIREBASE_PROJECT_ID=...
REACT_APP_FIREBASE_STORAGE_BUCKET=...
REACT_APP_FIREBASE_MESSAGING_SENDER_ID=...
REACT_APP_FIREBASE_APP_ID=...`}
          </pre>
        </div>
      </div>
    );
  }

  if (!securityPassed) {
    return (
      <div className="app-shell auth-shell">
        <div className="auth-card">
          <div className="auth-copy">
            <img className="app-logo auth-logo" src={logoSrc} alt="شعار التطبيق" />
            <p className="eyebrow">For Lojain</p>
            <h1>رسالة صغيرة قبل الدخول</h1>
            <p>هذا المكان سويته لك، جاوبي على السؤال وبعدها يفتح لك كل شيء.</p>
          </div>

          <form className="auth-form" onSubmit={handleSecurityCheck}>
            <label>
              سؤال مني لك
              <input type="text" value={securityQuestion} readOnly />
            </label>

            <label>
              جوابك الحلو
              <input
                type="text"
                value={securityInput}
                onChange={(event) => setSecurityInput(event.target.value)}
                placeholder="اكتبيه هنا"
                required
              />
            </label>

            {securityError ? <p className="error-text">{securityError}</p> : null}

            <button type="submit" className="primary-btn">
              افتحي مكاننا
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (!currentUser) {
    return (
      <div className="app-shell auth-shell">
        <div className="auth-card">
          <div className="auth-copy">
            <img className="app-logo auth-logo" src={logoSrc} alt="شعار التطبيق" />
            <p className="eyebrow"></p>
            <h1>هذا المكان كله لك</h1>
            <p>
              سويت لك هنا كلامي وذكرياتي وكل شيء جميل بيننا في مكان واحد.
            </p>
          </div>

          <form className="auth-form" onSubmit={handleAuth}>
            <div className="mode-switch">
              <button
                type="button"
                className={authMode === "login" ? "active" : ""}
                onClick={() => setAuthMode("login")}
              >
                رجوع لي
              </button>
              <button
                type="button"
                className={authMode === "signup" ? "active" : ""}
                onClick={() => setAuthMode("signup")}
              >
                أول مرة هنا
              </button>
            </div>

            <label>
              إيميلك
              <input
                type="email"
                value={email}
                onChange={(event) => setEmail(event.target.value)}
                placeholder="you@example.com"
                required
              />
            </label>

            <label>
              كلمة السر لك
              <input
                type="password"
                value={password}
                onChange={(event) => setPassword(event.target.value)}
                placeholder="********"
                required
              />
            </label>

            {authError ? <p className="error-text">{authError}</p> : null}
            {accessError ? <p className="error-text">{accessError}</p> : null}

            <button type="submit" className="primary-btn" disabled={authLoading}>
              {authLoading
                ? "أرتب لك الدخول..."
                : authMode === "login"
                  ? "ادخلي"
                  : "ابدئي"}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="app-shell">
      <div className="backdrop" />
      <main className="app-layout">
        <aside className="sidebar">
          <div>
            <img className="app-logo sidebar-logo" src={logoSrc} alt="شعار التطبيق" />
            <p className="eyebrow"></p>
            <h1>الى لوجي</h1>
            <p className="sidebar-copy">
              علشان تعرفين اني مستعد اسوي اي شي علشان اعجبك
            </p>
            <div className="update-card">
              <strong>نسختك الحالية: {APP_VERSION}</strong>
              <p>{updateInfo.message || "إذا سويت لك شيء جديد يطلع لك هنا."}</p>
              {updateInfo.available ? (
                <button className="primary-btn update-btn" onClick={openDownloadLink}>
                  حمّلي النسخة {updateInfo.latestVersion}
                </button>
              ) : null}
              <button className="ghost-btn update-check-btn" onClick={checkForUpdates}>
                {updateInfo.loading ? "أشيك لك..." : "شيكي إذا فيه شيء جديد"}
              </button>
            </div>
            {installPrompt && !isInstalled ? (
              <button className="primary-btn install-btn" onClick={handleInstallApp}>
                ثبتيه عندك
              </button>
            ) : null}
            {isInstalled ? <p className="install-note">صار التطبيق عندك على الجهاز.</p> : null}
          </div>

          <div className="user-pill">
            <span className="user-badge">{currentUser.email?.slice(0, 1).toUpperCase()}</span>
            <div>
              <strong>{currentUser.email}</strong>
              <p>هنا معي الآن</p>
            </div>
          </div>

          <nav className="section-nav">
            <button
              className={activeSection === "chat" ? "active" : ""}
              onClick={() => setActiveSection("chat")}
            >
              كلامي لك
            </button>
            <button
              className={activeSection === "memories" ? "active" : ""}
              onClick={() => setActiveSection("memories")}
            >
              ذكرياتنا
            </button>
            <button
              className={activeSection === "games" ? "active" : ""}
              onClick={() => setActiveSection("games")}
            >
              لعبتنا
            </button>
          </nav>

          <button className="ghost-btn" onClick={() => signOut(auth)}>
            خروج مؤقت
          </button>
        </aside>

        <section className="content-panel">
          {activeSection === "chat" ? (
            <div className="panel">
              <div className="panel-header">
                <div>
                  <p className="eyebrow">Words For You</p>
                  <h2>كلامي لك</h2>
                </div>
              </div>

              <div className="message-list">
                {messages.length ? (
                  messages.map((message) => {
                    const ownMessage = message.userId === currentUser.uid;
                    return (
                      <article
                        key={message.id}
                        className={`message-card ${ownMessage ? "own" : ""}`}
                      >
                        <strong>{ownMessage ? "أنا" : message.author}</strong>
                        <p>{message.text}</p>
                        <span>{formatStamp(message.createdAt)}</span>
                      </article>
                    );
                  })
                ) : (
                  <div className="empty-state">
                    <h3>ابدئي أول لحظة بيننا هنا</h3>
                    <p>كل كلمة تنحفظ هنا عشان ترجعين لها متى ما اشتقتِ.</p>
                  </div>
                )}
              </div>

              <form className="composer" onSubmit={handleSendMessage}>
                <textarea
                  value={chatMessage}
                  onChange={(event) => setChatMessage(event.target.value)}
                  placeholder="اكتبي لي أو خلي لي كلمة تبقى هنا..."
                />
                <button type="submit" className="primary-btn">
                  أرسليها لي
                </button>
              </form>
            </div>
          ) : null}

          {activeSection === "memories" ? (
            <div className="panel">
              <div className="panel-header">
                <div>
                  <p className="eyebrow">Moments For Us</p>
                  <h2>ذكرياتنا</h2>
                </div>
              </div>

              <form className="memory-form" onSubmit={handleAddMemory}>
                <input
                  value={memoryTitle}
                  onChange={(event) => setMemoryTitle(event.target.value)}
                  placeholder="اسم اللحظة"
                />
                <textarea
                  value={memoryText}
                  onChange={(event) => setMemoryText(event.target.value)}
                  placeholder="اكتبي شعورك أو وصف اللحظة"
                />
                <input
                  value={memoryImageUrl}
                  onChange={(event) => setMemoryImageUrl(event.target.value)}
                  placeholder="رابط صورة لو ودك"
                />
                <button type="submit" className="primary-btn">
                  احفظيها لنا
                </button>
              </form>

              <div className="memory-grid">
                {memories.length ? (
                  memories.map((memory) => (
                    <article key={memory.id} className="memory-card">
                      {memory.imageUrl ? (
                        <img src={memory.imageUrl} alt={memory.title} />
                      ) : null}
                      <div className="memory-copy">
                        <strong>{memory.title}</strong>
                        {memory.text ? <p>{memory.text}</p> : null}
                        <span>
                          {memory.author} • {formatStamp(memory.createdAt)}
                        </span>
                      </div>
                    </article>
                  ))
                ) : (
                  <div className="empty-state">
                    <h3>ما كتبنا ذكرى هنا إلى الآن</h3>
                    <p>أول صورة أو كلمة منك بتخلي هذا المكان أحلى.</p>
                  </div>
                )}
              </div>
            </div>
          ) : null}

          {activeSection === "games" ? (
            <div className="panel">
              <div className="panel-header">
                <div>
                  <p className="eyebrow">A Little Game For Us</p>
                  <h2>لعبتنا الصغيرة</h2>
                </div>
              </div>

              <div className="game-toolbar">
                <button className="primary-btn" onClick={() => joinAsPlayer("X")}>
                  ابدئي بـ X
                </button>
                <button className="primary-btn alt" onClick={() => joinAsPlayer("O")}>
                  ابدئي بـ O
                </button>
                <button className="ghost-btn" onClick={resetGame}>
                  نعيدها من جديد
                </button>
              </div>

              <div className="game-status">
                <p>
                  الدور الآن: <strong>{game.nextTurn}</strong>
                </p>
                <p>
                  أنتِ تلعبين كـ: <strong>{currentPlayerSymbol || "تشوفين فقط"}</strong>
                </p>
                <p>
                  حالة اللعبة:{" "}
                  <strong>
                    {game.winner === "draw"
                      ? "تعادل بيننا"
                      : game.winner
                        ? `الفائزة ${game.winner}`
                        : "لسه اللعب مستمر"}
                  </strong>
                </p>
              </div>

              <div className="board">
                {game.board.map((cell, index) => (
                  <button
                    key={index}
                    type="button"
                    className="square"
                    onClick={() => handleSquareClick(index)}
                  >
                    {cell}
                  </button>
                ))}
              </div>

              <div className="players-grid">
                <div className="player-card">
                  <span>X</span>
                  <p>{game.players?.X?.email || "بانتظارك هنا"}</p>
                </div>
                <div className="player-card">
                  <span>O</span>
                  <p>{game.players?.O?.email || "بانتظارك هنا"}</p>
                </div>
              </div>
            </div>
          ) : null}
        </section>
      </main>
    </div>
  );
}

export default App;
